import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import {
  generateCreateInput,
  generateEnum,
  generateHeader,
  generateModelInterface,
  generateRestClientClass,
  generateUpdateInput,
  generateWhereUniqueInput,
} from './template'

/** Generates a typed REST API client file from the DMMF in the provided generator options. */
export async function generate(options: GeneratorOptions): Promise<void> {
  const { dmmf, generator } = options

  const outputDir = generator.output?.value
  if (!outputDir) {
    throw new Error('@prisma/generator-rest-client requires an output path. Add `output = "./generated/rest-client"` to your generator block.')
  }

  const models = dmmf.datamodel.models
  const enums = dmmf.datamodel.enums
  const enumNames = new Set(enums.map((e) => e.name))

  const parts: string[] = []

  // Header with config interface and request helper
  const baseUrl = generator.config['baseUrl'] as string | undefined
  parts.push(generateHeader(baseUrl ?? 'http://localhost:3000/api'))

  // Enum declarations
  for (const enumDef of enums) {
    parts.push(generateEnum(enumDef))
  }

  // Model interfaces and input types
  for (const model of models) {
    parts.push(generateModelInterface(model, enumNames))
    parts.push(generateCreateInput(model, enumNames))
    parts.push(generateUpdateInput(model, enumNames))
    parts.push(generateWhereUniqueInput(model, enumNames))
  }

  // RestClient class with CRUD methods per model
  parts.push(generateRestClientClass(models))

  const output = parts.join('\n')

  await fs.promises.mkdir(outputDir, { recursive: true })
  await fs.promises.writeFile(path.join(outputDir, 'rest-client.ts'), output, 'utf-8')
}

