import { generatorHandler } from '@prisma/generator-helper'

import { generate } from './generator'

generatorHandler({
  onManifest() {
    return {
      prettyName: 'Prisma REST Client Generator',
      defaultOutput: './generated/rest-client',
    }
  },
  async onGenerate(options) {
    await generate(options)
  },
})

import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import {
  generateCreateInput,
  generateEnum,
  generateHeader,
  generateModelInterface,
  generateRestClientClass,
  generateUpdateInput,
  generateWhereUniqueInput,
} from './template'

/** Generates a typed REST API client file from the DMMF in the provided generator options. */
export async function generate(options: GeneratorOptions): Promise<void> {
  const { dmmf, generator } = options

  const outputDir = generator.output?.value
  if (!outputDir) {
    throw new Error('@prisma/generator-rest-client requires an output path. Add `output = "./generated/rest-client"` to your generator block.')
  }

  const models = dmmf.datamodel.models
  const enums = dmmf.datamodel.enums
  const enumNames = new Set<string>(enums.map((e) => e.name as string))

  const parts: string[] = []

  // Header with config interface and request helper
  const baseUrl = generator.config['baseUrl'] as string | undefined
  parts.push(generateHeader(baseUrl ?? 'http://localhost:3000/api'))

  // Enum declarations
  for (const enumDef of enums) {
    parts.push(generateEnum(enumDef))
  }

  // Model interfaces and input types
  for (const model of models) {
    parts.push(generateModelInterface(model, enumNames))
    parts.push(generateCreateInput(model, enumNames))
    parts.push(generateUpdateInput(model, enumNames))
    parts.push(generateWhereUniqueInput(model, enumNames))
  }

  // RestClient class with CRUD methods per model
  parts.push(generateRestClientClass(models))

  const output = parts.join('\n')

  await fs.promises.mkdir(outputDir, { recursive: true })
  await fs.promises.writeFile(path.join(outputDir, 'rest-client.ts'), output, 'utf-8')
}

import type * as DMMF from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/** Maps a Prisma scalar/enum type name to its TypeScript representation. */
export function mapFieldType(field: DMMF.Field, enumNames: Set<string>): string {
  const base = resolveBaseType(field, enumNames)
  return field.isList ? `${base}[]` : base
}

function resolveBaseType(field: DMMF.Field, enumNames: Set<string>): string {
  if (field.kind === 'enum') {
    return enumNames.has(field.type) ? field.type : 'string'
  }

  if (field.kind === 'scalar') {
    return SCALAR_TYPE_MAP[field.type] ?? 'unknown'
  }

  // Object relations and unsupported types are not included in the REST interface
  return 'unknown'
}

/** Wraps a type string with `| null` when the field is optional. */
export function withNullability(tsType: string, field: DMMF.Field): string {
  return field.isRequired ? tsType : `${tsType} | null`
}

/** Generates the full `rest-client.ts` file content. */
export function generateHeader(baseUrl: string): string {
  return `// Generated by @prisma/generator-rest-client — do not edit manually

/**
 * Configuration for the REST API client.
 */
export interface RestClientConfig {
  /** Base URL of the REST API (e.g. "http://localhost:3000/api"). */
  baseUrl: string
  /** Optional headers to include with every request. */
  headers?: Record<string, string>
}

/**
 * Performs an HTTP request and returns the parsed JSON body.
 */
async function request<T>(config: RestClientConfig, method: string, path: string, body?: unknown): Promise<T> {
  const url = \`\${config.baseUrl}\${path}\`
  const init: RequestInit = {
    method,
    headers: {
      'Content-Type': 'application/json',
      ...config.headers,
    },
  }
  if (body !== undefined) {
    init.body = JSON.stringify(body)
  }
  const response = await fetch(url, init)
  if (!response.ok) {
    throw new Error(\`REST client request failed: \${method} \${url} responded with \${response.status}\`)
  }
  return response.json() as Promise<T>
}
`
}

/** Generates a TypeScript enum declaration from a DMMF enum. */
export function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${enumDef.name} {\n${members}\n}\n`
}

/** Generates a TypeScript interface from a DMMF model (scalar and enum fields only). */
export function generateModelInterface(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => {
      const tsType = withNullability(mapFieldType(f, enumNames), f)
      const optional = f.isRequired ? '' : '?'
      return `  ${f.name}${optional}: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}\n`
}

/** Generates the input type used for create/update operations (all fields optional except required non-id ones on create). */
export function generateCreateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .filter((f) => !f.isReadOnly && !f.isGenerated && !f.isUpdatedAt)
    .map((f) => {
      const tsType = withNullability(mapFieldType(f, enumNames), f)
      // ID fields with defaults and auto-increment are optional on create
      const optional = !f.isRequired || (f.isId && f.hasDefaultValue) ? '?' : ''
      return `  ${f.name}${optional}: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name}CreateInput {\n${fields}\n}\n`
}

/** Generates the input type used for update operations (all fields optional). */
export function generateUpdateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .filter((f) => !f.isReadOnly && !f.isGenerated && !f.isUpdatedAt)
    .map((f) => {
      const tsType = withNullability(mapFieldType(f, enumNames), f)
      return `  ${f.name}?: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name}UpdateInput {\n${fields}\n}\n`
}

/** Generates the where-unique input for findUnique/update/delete (id or unique fields). */
export function generateWhereUniqueInput(model: DMMF.Model, enumNames: Set<string>): string {
  const uniqueFields = model.fields.filter((f) => (f.isId || f.isUnique) && (f.kind === 'scalar' || f.kind === 'enum'))

  const fields = uniqueFields
    .map((f) => {
      const tsType = mapFieldType(f, enumNames)
      return `  ${f.name}?: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name}WhereUniqueInput {\n${fields}\n}\n`
}

/** Generates typed CRUD methods for a single model. */
export function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const resource = name.toLowerCase()

  return `  ${resource} = {
    /**
     * Find multiple ${name} records.
     */
    findMany: (): Promise<${name}[]> => {
      return request<${name}[]>(this.config, 'GET', '/${resource}')
    },

    /**
     * Find a unique ${name} record.
     */
    findUnique: (where: ${name}WhereUniqueInput): Promise<${name} | null> => {
      const key = Object.entries(where).find(([, v]) => v !== undefined)
      if (!key) throw new Error('At least one unique field must be provided')
      return request<${name} | null>(this.config, 'GET', \`/${resource}/\${encodeURIComponent(String(key[1]))}\`)
    },

    /**
     * Create a new ${name} record.
     */
    create: (data: ${name}CreateInput): Promise<${name}> => {
      return request<${name}>(this.config, 'POST', '/${resource}', data)
    },

    /**
     * Update an existing ${name} record.
     */
    update: (where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> => {
      const key = Object.entries(where).find(([, v]) => v !== undefined)
      if (!key) throw new Error('At least one unique field must be provided')
      return request<${name}>(this.config, 'PATCH', \`/${resource}/\${encodeURIComponent(String(key[1]))}\`, data)
    },

    /**
     * Delete a ${name} record.
     */
    delete: (where: ${name}WhereUniqueInput): Promise<${name}> => {
      const key = Object.entries(where).find(([, v]) => v !== undefined)
      if (!key) throw new Error('At least one unique field must be provided')
      return request<${name}>(this.config, 'DELETE', \`/${resource}/\${encodeURIComponent(String(key[1]))}\`)
    },
  }
`
}

/** Generates the main RestClient class that aggregates all model clients. */
export function generateRestClientClass(models: readonly DMMF.Model[]): string {
  const modelClients = models.map((m) => generateModelClient(m)).join('\n')

  return `/**
 * Typed REST API client generated from the Prisma schema.
 */
export class RestClient {
  constructor(private readonly config: RestClientConfig) {}

${modelClients}}
`
}

